package src.org.apache.cassandra.db;

public class SliceByNamesReadCommand extends ReadCommand { public final SortedSet < ByteBuffer > columnNames ; public SliceByNamesReadCommand ( String table , ByteBuffer key , ColumnParent column_parent , Collection < ByteBuffer > columnNames ) { this ( table , key , new QueryPath ( column_parent ) , columnNames ) ; } public SliceByNamesReadCommand ( String table , ByteBuffer key , QueryPath path , Collection < ByteBuffer > columnNames ) { super ( table , key , path , CMD_TYPE_GET_SLICE_BY_NAMES ) ; this . columnNames = new TreeSet < ByteBuffer > ( getComparator ( ) ) ; this . columnNames . addAll ( columnNames ) ; } @ Override public ReadCommand copy ( ) { ReadCommand readCommand = new SliceByNamesReadCommand ( table , key , queryPath , columnNames ) ; readCommand . setDigestQuery ( isDigestQuery ( ) ) ; return readCommand ; } @ Override public Row getRow ( Table table ) throws IOException { DecoratedKey dk = StorageService . getPartitioner ( ) . decorateKey ( key ) ; return table . getRow ( QueryFilter . getNamesFilter ( dk , queryPath , columnNames ) ) ; } @ Override public String toString ( ) { return "SliceByNamesReadCommand(" + "table='" + table + '\'' + ", key=" + ByteBufferUtil . bytesToHex ( key ) + ", columnParent='" + queryPath + '\'' + ", columns=[" + getComparator ( ) . getString ( columnNames ) + "]" + ')' ; } }